const listManagerLeaveReportRows = `-- name: ListManagerLeaveReportRows :many
SELECT
    l.id,
    l.tenant_id,
    l.user_id,
    e.employee_code,
    e.firstname,
    e.lastname,
    e.reporting_manager_id,
    e.department_id,
    d.name AS department_name,
    e.designation_id,
    dg.name AS designation_name,
    l.leave_type_id,
    lt.name AS leave_type_name,
    lt.shortcode AS leave_type_shortcode,
    l.fy_id,
    fy.name AS financial_year_name,
    l.start_date,
    l.end_date,
    l.start_day_type,
    l.end_day_type,
    l.days,
    l.reason,
    l.status,
    l.is_sandwich,
    l.applied_date,
    l.created_at,
    l.updated_at
FROM hrms.leaves l
JOIN hrms.employees e ON e.tenant_id = l.tenant_id AND e.user_id = l.user_id AND NOT e.inactive
LEFT JOIN hrms.departments d ON d.tenant_id = e.tenant_id AND d.id = e.department_id AND NOT d.inactive
LEFT JOIN hrms.designations dg ON dg.tenant_id = e.tenant_id AND dg.id = e.designation_id AND NOT dg.inactive
LEFT JOIN hrms.leave_types lt ON lt.tenant_id = l.tenant_id AND lt.id = l.leave_type_id AND NOT lt.inactive
LEFT JOIN hrms.financial_years fy ON fy.tenant_id = l.tenant_id AND fy.id = l.fy_id AND NOT fy.inactive
WHERE l.tenant_id = $1
  AND e.reporting_manager_id = $2
  AND NOT l.inactive
  AND ($3::uuid IS NULL OR l.fy_id = $3::uuid)
  AND ($4::uuid IS NULL OR l.user_id = $4::uuid)
  AND ($5::uuid IS NULL OR e.department_id = $5::uuid)
  AND ($6::uuid IS NULL OR l.leave_type_id = $6::uuid)
  AND ($7::text IS NULL OR l.status = $7::text)
  AND ($8::date IS NULL OR l.end_date >= $8::date)
  AND ($9::date IS NULL OR l.start_date <= $9::date)
ORDER BY l.start_date DESC, l.applied_date DESC
`

